VALUES
  ('optometrist-moex-02004', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '落球測試（dropballtest）是用於測試玻璃鏡片耐撞擊力（impactresistance），但下列何種鏡片不需要進行 落球測試？', '["-1.00D單光變色稜鏡削薄玻璃鏡片（slab-offlenses）", "+1.75D富蘭克林（E型）冕玻璃雙光鏡片", "縮徑白內障鏡片（lenticularcataractlenses)", "-5.00D單光冕玻璃鏡片"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "a1cbaa126f94", "answer_pdf_sha1": "06dd7a319b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02005', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '張先生有一副眼鏡，鏡片形狀為圓形，鏡架是以方框法（theboxingsystem）測量與標記，當有效直徑 （effectivediameterofthelens,ED）為62mm時，則其標示可能為下列何者？', '["54□15", "58□16", "62□17", "66□18"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "a1cbaa126f94", "answer_pdf_sha1": "06dd7a319b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02006', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '若有一患者鼻墊的上半部邊緣較緊貼鼻部，造成患者鼻部疼痛與不適，則應該如何調整鏡架，才可避免造 成患者鼻部所留下的壓痕？', '["將兩鼻墊底端分開改變前角", "將前角位置更為垂直", "需增加下半部鼻墊張角", "替換成矽膠材質鼻墊"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "a1cbaa126f94", "answer_pdf_sha1": "06dd7a319b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02007', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '配戴者的瞳距（PD）為64mm，鏡框的A尺寸為52mm，鼻橋尺寸為18mm，有效直徑為58mm，則配 戴者的每個鏡片所需的水平移心量為何？', '["右眼水平移心量為3mm，左眼水平移心量為2mm", "右眼水平移心量為5mm，左眼水平移心量為4mm", "右眼水平移心量為4mm，左眼水平移心量為2mm", "右眼水平移心量為4mm，左眼水平移心量為3mm"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "a1cbaa126f94", "answer_pdf_sha1": "06dd7a319b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02008', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '配鏡時需要考慮個別化的設計，下列敘述何者正確？', '["瞳孔間距較大的病患，在閱讀時，眼球內聚移動的幅度較瞳孔間距小者為少", "工作距離近的人，在閱讀時，眼球內聚移動的幅度較工作距離遠者為少", "遠視眼的病患，在閱讀時，眼球內聚移動的幅度較近視眼者為大", "漸進多焦點鏡片硬式設計較軟式設計容易適應"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "a1cbaa126f94", "answer_pdf_sha1": "06dd7a319b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02009', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '患者左眼處方為 -5.00DS/+3.00DC×090，在瞳孔中心處產生2 base90及1 base180的稜鏡效應，求水 平方向及垂直方向的移心量與移動方向？ △ △', '["垂直方向5mm，向上移；水平方向4mm，向內移", "垂直方向4mm，向下移；水平方向5mm，向外移", "垂直方向6mm，向上移；水平方向3mm，向內移", "垂直方向3mm，向下移；水平方向6mm，向外移"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "a1cbaa126f94", "answer_pdf_sha1": "06dd7a319b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02010', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有一稜鏡由折射率1.5的材質所製成，其頂角呈6度，利用薄稜鏡的近似值，其偏移角為多少度？', '["2.2度", "3度", "3.8度", "4度"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "a1cbaa126f94", "answer_pdf_sha1": "06dd7a319b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02011', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '若患者鏡框之有效直徑（effectivediameter,ED）為52mm，當其單眼PD由鏡框水平的幾何中心（geometrical center,GC）向鼻側內移5mm時，至少須以多大直徑之鏡片裝框？', '["52mm", "62mm", "64mm", "66mm"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "a1cbaa126f94", "answer_pdf_sha1": "06dd7a319b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02012', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '配鏡處方OD：-8.00DS，OS：-10.00DS，PD：64mm，欲以移動光學中心的方式產生2 BI，且稜鏡量平 均分配給兩眼的鏡片，眼鏡的光學中心應該是多少？ △', '["66.25mm", "68.5mm", "61.75mm", "59.5mm"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "a1cbaa126f94", "answer_pdf_sha1": "06dd7a319b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 42, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02013', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關鏡框的調整，下列何者正確？', '["鏡框校準的順序為先調鏡腳再調框面再調鼻墊", "當眼鏡左高右低時，將左邊鏡腳往下調整", "當鏡框右邊比較貼臉時，將右鏡腳往內調整", "將左右兩鏡腳往上調整，可以增加前傾角（pantoscopictilt）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "a1cbaa126f94", "answer_pdf_sha1": "06dd7a319b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 43, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
